#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    qsort(arr, n, sizeof(int), compare);
    int median = arr[n / 2];
    int moves = 0;
    for (int i = 0; i < n; i++) {
        moves += abs(arr[i] - median);
    }
    printf("%d\n", moves);
    return 0;
}

